={{ (() => {
  const cfgItem = $items('SetConfig', 0, 0) || { json: {} };
  const cfg = cfgItem.json || {};
  const brand = cfg.BRAND || {};
  const primary = $json.primary || {};
  const related = Array.isArray($json.related) ? $json.related : [];
  const relatedLines = related.length ? related.map(r => `- ${r.title || ''} (${r.url || ''})`).join('\n') : '- 无参考';
  const primaryTextItem = $items('ReadPrimary', 0, 0) || { json: '' };
  const articleTextRaw = primaryTextItem.json;
  const articleText = typeof articleTextRaw === 'string' ? articleTextRaw : JSON.stringify(articleTextRaw || '');
  const palette = Array.isArray(brand.palette) ? brand.palette : [];
  const brandBlock = `BRAND: palette=${JSON.stringify(palette)}, style=${brand.style || ''}, negatives=${brand.negatives || ''}`;
  const systemMessage = '你是分析师与评论员。输出一个 JSON：{markdown, prompts}；markdown=中文Markdown 1200-1600字；prompts=长度4数组：封面+3个关键观点图像提示（包含构图/隐喻/2-3主色/风格标记，禁止真实人物/商标）。风格与色板来自提供的 BRAND。';
  const userMessage = `主要文章：${primary.title || ''}\n来源：${primary.source || ''}\n链接：${primary.url || ''}\n发布时间：${primary.publishedAt || ''}\n作者：${primary.author || ''}\n摘要：${primary.description || ''}\n\n正文全文（若缺失请谨慎）：\n${articleText}\n\n相关参考（仅标题与链接）：\n${relatedLines}\n\n${brandBlock}`;
  const payload = {
    model: cfg.OPENAI_CHAT || 'gpt-4o-mini',
    temperature: 0.4,
    response_format: { type: 'json_object' },
    messages: [
      { role: 'system', content: systemMessage },
      { role: 'user', content: userMessage }
    ]
  };
  return JSON.stringify(payload);
})() }}

