const choices = Array.isArray($json.choices) ? $json.choices : [];
function extractText(entry) {
  if (!entry) return '';
  const content = entry.message?.content;
  if (Array.isArray(content)) {
    return content.map(part => {
      if (typeof part === 'string') return part;
      if (typeof part?.text === 'string') return part.text;
      if (typeof part?.value === 'string') return part.value;
      if (typeof part === 'object') {
        if (typeof part?.content === 'string') return part.content;
        if (typeof part?.content?.text === 'string') return part.content.text;
      }
      return '';
    }).join('').trim();
  }
  if (typeof content === 'string') return content;
  return '';
}
const combined = choices
  .map(extractText)
  .filter(Boolean)
  .join('
')
  .trim();
let payload = { markdown: '', prompts: [] };
if (combined) {
  try {
    payload = JSON.parse(combined);
  } catch (error) {
    const match = combined.match(/\{[\s\S]*\}/);
    if (match) {
      try {
        payload = JSON.parse(match[0]);
      } catch (innerError) {
        payload = { markdown: combined, prompts: [] };
      }
    } else {
      payload = { markdown: combined, prompts: [] };
    }
  }
}
return [{ json: { payload, raw: combined } }];

const cfgItem = $items('SetConfig', 0, 0) || { json: {} };
const cfg = cfgItem.json || {};
const parseItem = $items('ParseLLMPayload', 0, 0) || { json: {} };
const payload = parseItem.json ? (parseItem.json.payload || {}) : {};
const prompts = Array.isArray(payload.prompts) ? payload.prompts.filter(p => typeof p === 'string' && p.trim()) : [];
if (!prompts.length) {
  throw new Error('LLM response did not provide image prompts');
}
const coverSize = cfg.COVER_SIZE || '1024x576';
const bodySize = cfg.BODY_SIZE || '1024x1024';
const slots = prompts.slice(0, 4).map((prompt, idx) => ({
  role: idx === 0 ? 'cover' : `keypoint${idx}`,
  prompt: prompt.trim(),
  size: idx === 0 ? coverSize : bodySize
}));
return slots.map(slot => ({ json: slot }));

const previousItems = $items('CollectImgs', 0, 0, { returnAll: true }) || [];
const previous = previousItems.map(item => item.json).filter(Boolean);
const response = items[0] ? (items[0].json || {}) : {};
const dataArray = Array.isArray(response.data) ? response.data : [];
const dataEntry = dataArray.length ? (dataArray[0] || {}) : {};
let imageRef = dataEntry.url || dataEntry.b64_json || null;
if (imageRef && !/^https?:\/\//i.test(imageRef)) {
  imageRef = 'data:image/png;base64,' + String(imageRef).replace(/\s+/g, '');
}
const splitItem = $items('Split', 0, 0) || { json: {} };
const slot = splitItem.json || {};
const record = {
  role: slot.role,
  size: slot.size,
  prompt: slot.prompt,
  url: imageRef
};
const payload = [...previous.filter(entry => entry.role !== record.role), record];
return payload.map((entry, index) => ({ json: { ...entry, index } }));

const parseItem = $items('ParseLLMPayload', 0, 0) || { json: {} };
const payload = parseItem.json ? (parseItem.json.payload || {}) : {};
const markdown = payload.markdown || '';
const collectItems = $items('CollectImgs', 0, 0, { returnAll: true }) || [];
const imgs = collectItems.map(item => item.json).filter(Boolean);
const byRole = Object.fromEntries(imgs.filter(img => img && img.role).map(img => [img.role, img]));
let output = '';
const cover = byRole.cover;
if (cover && cover.url) {
  output += `![\u5c01\u9762](${cover.url})\n\n`;
}
output += markdown.trim();
const keypoints = Object.keys(byRole).filter(role => role.startsWith('keypoint')).sort();
if (keypoints.length) {
  output += '\n';
  keypoints.forEach((role, idx) => {
    const image = byRole[role];
    if (image && image.url) {
      const label = image.prompt ? image.prompt.slice(0, 80) : `\u56fe ${idx + 1}`;
      output += `\n![${label}](${image.url})\n`;
    }
  });
}
return [{ json: { markdown: output.trim() } }];

function slugify(s){return (s||'ai-commentary').toLowerCase().replace(/[^a-z0-9\u4e00-\u9fa5]+/g,'-').replace(/^-+|-+$/g,'').slice(0,60)||'ai';}
const assembleItem = $items('AssembleMD',0,0) || { json: {} };
const markdown = assembleItem.json.markdown || '';
const scoreItem = $items('ScoreSelect',0,0) || { json: {} };
const fallbackTitle = scoreItem.json.primary ? (scoreItem.json.primary.title || 'AI 评论') : 'AI 评论';
const titleMatch = markdown.match(/^#\s*(.+)$/m);
const title = titleMatch ? titleMatch[1] : fallbackTitle;
const d = new Date(); const yyyy=d.getFullYear(), mm=String(d.getMonth()+1).padStart(2,'0'), dd=String(d.getDate()).padStart(2,'0');
const filepath = `content/${yyyy}-${mm}-${dd}-${slugify(title)}.md`;
const content = Buffer.from(markdown,'utf8').toString('base64');
const message = `feat(post): ${yyyy}-${mm}-${dd} ${title}`;
return [{json:{filepath, content, message}}];
